SELECT 
    COUNT(*) 
FROM
    (SELECT 
        a1.* 
    FROM
        prob_restore a1 
        LEFT JOIN prob_restore_process a4 
            ON a1.processId = a4.id 
    WHERE a1.probId = #{probId}

	<if test=" prepend="and" assignee>

			(a1.assignee = #{assignee} 

		<if test=" prepend="OR" areapower>

				(a1.officeCode in ($areapower$) 

				<if test=" prepend="and" assigneeRole> a1.assigneeRole = #{assigneeRole}  
				)

		)


	<if test=" prepend="and" officeCode> a1.officeCode = #{officeCode}
	<if test=" prepend="and" projectName> a1.projectName like concat('%', #{projectName}, '%')
	<if test=" prepend="and" serialNum> a1.serialNum = #{serialNum} 
	<if test=" prepend="and" itemModel> a1.itemModel like concat(#{itemModel}, '%')
	<if test=" prepend="and" contractNo> a1.contractNo = #{contractNo}
	<if test=" prepend="and" restoreStatus compareValue="0">
		 a4.restoreStatus = #{restoreStatus}

	GROUP BY a1.projectId, a1.assignee, a1.assigneeRole, a4.restoreStatus ) t


	SELECT count(*) FROM prob_restore a1
	left join prob_restore_process a4 on a1.processId = a4.id
	WHERE a1.probId = #{probId}

<if test=" prepend="and" assignee>

