mapper.insert:
CREATE TEMPORARY TABLE softChangeLog_tempTable SELECT sv.`projectId`, fi.`itemname`, CONCAT( CASE WHEN fsv.`serial_number` IS NULL THEN "出厂版本信息:[无];
" ELSE CONCAT( "出厂版本信息:[conp:", fsv.`conp`, ",cpld:", fsv.`cpld`, ",boot:", fsv.`boot`, ",pcb:", fsv.`pcb`, "];
" ) END, GROUP_CONCAT( DISTINCT CONCAT( IFNULL(sv.createBy, ""), "-", IFNULL(ui.realName, ""), " ", scl.`createTime`, "：", scl.changeRemark, "，conp:[", CASE WHEN sv.`conpChange` = 1 THEN CONCAT( SUBSTRING_INDEX(sv.`conpBak`, "->", - 1), "->", sv.`conp` ) ELSE sv.`conp` END, "]", "，cpld:[", CASE WHEN sv.`cpldChange` = 1 THEN CONCAT( SUBSTRING_INDEX(sv.`cpldBak`, "->", - 1), "->", sv.`cpld` ) ELSE sv.`cpld` END, "]", "，boot:[", CASE WHEN sv.`bootChange` = 1 THEN CONCAT( SUBSTRING_INDEX(sv.`bootBak`, "->", - 1), "->", sv.`boot` ) ELSE sv.`boot` END, "]", "，pcb:[", CASE WHEN sv.`pcbChange` = 1 THEN CONCAT( SUBSTRING_INDEX(sv.`pcbBak`, "->", - 1), "->", sv.`pcb` ) ELSE sv.`pcb` END, "]" ) SEPARATOR ";
" ) ) AS softInfo, COUNT(DISTINCT sv.id) AS updateCount, MAX(ps.`probId`) AS probId, MAX(sv.`executeTime`) AS executeTime FROM pm_project_soft_version sv LEFT JOIN pm_project_soft_change_logs scl ON sv.`projectId` = scl.projectId AND sv.`logId` = scl.id LEFT JOIN fb_items fi ON fi.`item` = SUBSTR(sv.`barcode`, 1, 8) LEFT JOIN fb_soft_version fsv ON sv.`barcode` = fsv.`serial_number` LEFT JOIN `prob_softwares` ps ON CASE WHEN ps.`conp` IS NOT NULL THEN ps.`conp` = SUBSTRING_INDEX(sv.`conpBak`, "->", - 1) ELSE 1 = 1 END AND CASE WHEN ps.`cpld` IS NOT NULL THEN ps.`cpld` = SUBSTRING_INDEX(sv.`cpldBak`, "->", - 1) ELSE 1 = 1 END AND CASE WHEN ps.`boot` IS NOT NULL THEN ps.`boot` = SUBSTRING_INDEX(sv.`bootBak`, "->", - 1) ELSE 1 = 1 END AND CASE WHEN ps.`pcb` IS NOT NULL THEN ps.`pcb` = SUBSTRING_INDEX(sv.`pcbBak`, "->", - 1) ELSE 1 = 1 END AND ps.manualEntry IS NULL AND ps.`datastate` = 1 LEFT JOIN `fnd_user_info` ui ON ui.username = sv.createBy WHERE sv.`executeTime` >= #{startTime} <if test=" prepend="and" endTime> sv.`executeTime` <= CONCAT(#{endTime}, ' 23:59:59')
and (sv.`conpChange` = 1 or sv.`bootChange` = 1 or sv.`cpldChange` = 1 or sv.`pcbChange` = 1) <if test=" version> <if test=" prepend="AND" property="version.conp"> sv.conp = #version.conp# <if test=" prepend="AND" property="version.boot"> sv.boot = #version.boot# <if test=" prepend="AND" property="version.cpld"> sv.cpld = #version.cpld# <if test=" prepend="AND" property="version.pcb"> sv.pcb = #version.pcb#
GROUP BY sv.`projectId`, sv.`barcode`

