    <if test=" prepend="and" programManagerCode> (programManagerCodeA = #{programManagerCode} or programManagerCodeB = #{programManagerCode}) 
    <if test=" prepend="and" serviceManagerCode> serviceManagerCode = #{serviceManagerCode}

