        INSERT INTO `prob_read_log`
        SELECT 
            null, #{probId}, #{reader}, NOW(), GREATEST(IFNULL(MAX(status), #{status}), #{status}), 
		    IFNULL(MIN(readTime), now()) AS firstTime, 
		    IFNULL(Max(commitTime), IF(#{status} = 1, now(), null)) AS commitTime
		FROM
		    `prob_read_log` 
		WHERE probId = #{probId} 
		    AND reader = #{reader}

            SELECT last_insert_id() as id ;

