SELECT p.probNum, p.`theme`, p.`watch`, bd1.`basicDataName` AS watchName, p.`status`, bd2.`basicDataName` AS statusName, ui.`username` AS render, CONCAT(ui.username, "-", ui.realName) AS readerName, rl.firstTime, rl.commitTime, rl.readStatus FROM prob_main p LEFT JOIN `fnd_user_info` ui ON FALSE = FIND_IN_SET(ui.`roleIds`, ";1;,;9;,;20;") LEFT JOIN (SELECT probId, reader, MIN(readTime) AS firstTime, MAX(commitTime) AS commitTime, IFNULL(MAX(STATUS), 0) AS readStatus FROM prob_read_log GROUP BY `probId`, `reader`) rl ON ui.`username` = rl.`reader` LEFT JOIN fnd_basic_data bd1 ON p.`watch` = bd1.`basicDataId` AND bd1.`dataTypeCode` = '30' AND bd1.`effectiveTo` IS NULL LEFT JOIN fnd_basic_data bd2 ON p.`priority` = bd2.`basicDataId` AND bd2.`dataTypeCode` = '32' LEFT JOIN fnd_basic_data bd3 ON p.`status` = bd3.basicDataId AND bd3.dataTypeCode = '31' AND bd3.`effectiveTo` IS NULL
<if test=" prepend="and" property="prob.probNum"> p.probNum = #{probNum} <if test=" prepend="and" property="prob.theme"> p.theme = #{theme} <if test=" prepend="and" property="probReadLog.reader"> p.probNum = #{probNum} <if test=" prepend="and" probNum> p.probNum = #{probNum}
