<if test=" prepend="and" probNum> p.probNum = #{probNum} <if test=" prepend="and" theme> p.theme = #{theme} <if test=" prepend="and" probNum> p.probNum = #{probNum} <if test=" prepend="and" probNum> p.probNum = #{probNum}
ORDER BY p.visibleRange, p.`id`

