    <if test=" prepend="," createBy> `createBy` = #{createBy} 
    <if test=" prepend="," createTime> `createTime` = #{createTime} 
    <if test=" prepend="," updateBy> `updateBy` = #{updateBy} 
    <if test=" prepend="," updateTime> `updateTime` = #{updateTime} 

WHERE probId = #{probId}
